"use strict";

// prisma/seed.ts
var import_config = require("dotenv/config");

// src/lib/db/prisma.ts
var import_client = require("@prisma/client");
var globalForPrisma = globalThis;
function getProvider() {
  const url = process.env.DATABASE_URL || "";
  if (url.startsWith("postgresql://") || url.startsWith("postgres://")) {
    return "postgresql";
  }
  return "sqlite";
}
function createPrismaClient() {
  const provider = getProvider();
  if (provider === "postgresql") {
    try {
      const { Pool } = require("pg");
      const { PrismaPg } = require("@prisma/adapter-pg");
      const pool = new Pool({ connectionString: process.env.DATABASE_URL });
      const adapter = new PrismaPg(pool);
      return new import_client.PrismaClient({ adapter });
    } catch (error) {
      console.error(
        "[prisma] PostgreSQL mode requested but pg/adapter not available.",
        error
      );
      throw new Error(
        "PostgreSQL mode requires 'pg' and '@prisma/adapter-pg' packages. Install them or switch to SQLite with DATABASE_URL=file:./db.sqlite"
      );
    }
  }
  return new import_client.PrismaClient();
}
var db = globalForPrisma.prisma ?? createPrismaClient();
if (process.env.NODE_ENV !== "production") {
  globalForPrisma.prisma = db;
}

// src/lib/db/json-helper.ts
function stringifyJsonField(value) {
  if (typeof value === "string") {
    try {
      JSON.parse(value);
      return value;
    } catch {
      return JSON.stringify(value);
    }
  }
  return JSON.stringify(value);
}

