// prisma/notes/2.1 Data Structures/Dictionaries/iterating-dictionaries.ts
var iteratingDictionariesLesson = {
  title: "Iterating Through Dictionaries",
  slug: "iterating-dictionaries",
  content: `# Iterating Through Dictionaries

Python provides several ways to iterate over dictionaries. Choosing the right method makes your code cleaner and more efficient.

## Method 1: Iterate Over Keys (Default)

By default, iterating over a dictionary gives you the keys:

\`\`\`python
person = {"name": "Alice", "age": 25, "city": "New York"}

# These are equivalent
for key in person:
    print(key)

for key in person.keys():
    print(key)
\`\`\`

Output:
\`\`\`
name
age
city
\`\`\`

\`\`\`python
# Access values through keys
for key in person:
    print(f"{key}: {person[key]}")
\`\`\`

## Method 2: Iterate Over Values

Use \`.values()\` when you only need the values:

\`\`\`python
scores = {"Alice": 88, "Bob": 72, "Charlie": 95}

for score in scores.values():
    print(score)
# Output: 88  72  95

# Calculate statistics
total = sum(scores.values())
average = total / len(scores)
maximum = max(scores.values())
print(f"Average: {average:.1f}, Max: {maximum}")
\`\`\`

## Method 3: Iterate Over Key-Value Pairs (Most Common)

Use \`.items()\` to get both key and value at once - this is the most common pattern:

\`\`\`python
person = {"name": "Alice", "age": 25, "city": "New York"}

for key, value in person.items():
    print(f"{key}: {value}")
\`\`\`

Output:
\`\`\`
name: Alice
age: 25
city: New York
\`\`\`

\`\`\`python
scores = {"Alice": 88, "Bob": 45, "Charlie": 92, "Diana": 67}

for name, score in scores.items():
    if score >= 60:
        status = "Pass"
    else:
        status = "Fail"
    print(f"{name:<10}: {score:>5}  [{status}]")
\`\`\`

Output:
\`\`\`
Alice     :    88  [Pass]
Bob       :    45  [Fail]
Charlie   :    92  [Pass]
Diana     :    67  [Pass]
\`\`\`

## Iterating in Sorted Order

Dictionaries maintain insertion order but you can iterate in a different order:

\`\`\`python
scores = {"Charlie": 92, "Alice": 88, "Bob": 45, "Diana": 67}

# Sort by key (alphabetically)
for name in sorted(scores):
    print(f"{name}: {scores[name]}")

# Sort by value (ascending)
for name, score in sorted(scores.items(), key=lambda x: x[1]):
    print(f"{name}: {score}")

# Sort by value (descending)
for name, score in sorted(scores.items(), key=lambda x: x[1], reverse=True):
    print(f"{name}: {score}")
\`\`\`

Output (descending):
\`\`\`
Charlie: 92
Alice: 88
Diana: 67
Bob: 45
\`\`\`

## Iterating with enumerate()

\`\`\`python
menu = {"Burger": 8.99, "Pizza": 12.99, "Salad": 6.99, "Soda": 1.99}

for i, (item, price) in enumerate(menu.items(), 1):
    print(f"{i}. {item:<10} \${price:.2f}")
\`\`\`

Output:
\`\`\`
1. Burger     $8.99
2. Pizza      $12.99
3. Salad      $6.99
4. Soda       $1.99
\`\`\`

## Filtering While Iterating

\`\`\`python
inventory = {
    "laptop":   {"price": 999, "stock": 15},
    "mouse":    {"price": 29,  "stock": 0},
    "keyboard": {"price": 79,  "stock": 8},
    "monitor":  {"price": 349, "stock": 0},
}

# In-stock items only
print("In Stock:")
for name, data in inventory.items():
    if data["stock"] > 0:
        print(f"  {name}: {data['stock']} units @ \${data['price']}")

# Out-of-stock items
out_of_stock = [name for name, data in inventory.items() if data["stock"] == 0]
print(f"\\nOut of stock: {out_of_stock}")
\`\`\`

## Modifying a Dictionary While Iterating

> [!IMPORTANT]
> Never add or remove keys while iterating - it causes a RuntimeError.

\`\`\`python
scores = {"Alice": 88, "Bob": 45, "Charlie": 92, "Diana": 58}

# WRONG - causes RuntimeError
# for name in scores:
#     if scores[name] < 60:
#         del scores[name]   # RuntimeError!

# CORRECT - iterate over a copy
for name in list(scores.keys()):
    if scores[name] < 60:
        del scores[name]
print(scores)   # Output: {'Alice': 88, 'Charlie': 92}

# ALSO CORRECT - build a new dict
scores = {"Alice": 88, "Bob": 45, "Charlie": 92, "Diana": 58}
scores = {name: score for name, score in scores.items() if score >= 60}
print(scores)   # Output: {'Alice': 88, 'Charlie': 92}
\`\`\`

## Iterating Nested Dictionaries

\`\`\`python
students = {
    "alice": {"math": 92, "science": 88, "english": 95},
    "bob":   {"math": 75, "science": 82, "english": 70},
    "charlie":{"math": 98, "science": 94, "english": 91},
}

print(f"{'Name':<10} {'Math':>6} {'Science':>8} {'English':>8} {'Avg':>6}")
print("-" * 42)

for name, grades in students.items():
    avg = sum(grades.values()) / len(grades)
    print(f"{name:<10} {grades['math']:>6} {grades['science']:>8} {grades['english']:>8} {avg:>6.1f}")
\`\`\`

Output:
\`\`\`
Name        Math  Science  English     Avg
------------------------------------------
alice         92       88       95    91.7
bob           75       82       70    75.7
charlie       98       94       91    94.3
\`\`\`

## Using zip() with Dictionaries

\`\`\`python
names  = ["Alice", "Bob", "Charlie"]
scores = [88, 72, 95]

# Create dict from two lists
student_scores = dict(zip(names, scores))
print(student_scores)
# Output: {'Alice': 88, 'Bob': 72, 'Charlie': 95}

# Iterate two dicts in parallel using zip
scores_2023 = {"Alice": 88, "Bob": 72, "Charlie": 95}
scores_2024 = {"Alice": 92, "Bob": 78, "Charlie": 89}

for (name, score_23), (_, score_24) in zip(scores_2023.items(), scores_2024.items()):
    change = score_24 - score_23
    arrow = "up" if change > 0 else "down" if change < 0 else "same"
    print(f"{name}: {score_23} -> {score_24} ({arrow} by {abs(change)})")
\`\`\`

Output:
\`\`\`
Alice: 88 -> 92 (up by 4)
Bob: 72 -> 78 (up by 6)
Charlie: 95 -> 89 (down by 6)
\`\`\`

## Practical Example: Sales Report

\`\`\`python
sales = {
    "Q1": {"Jan": 12500, "Feb": 11200, "Mar": 15800},
    "Q2": {"Apr": 13400, "May": 16700, "Jun": 14900},
    "Q3": {"Jul": 11800, "Aug": 13200, "Sep": 15100},
    "Q4": {"Oct": 17200, "Nov": 19800, "Dec": 22500},
}

print("=" * 50)
print(f"{'ANNUAL SALES REPORT':^50}")
print("=" * 50)

annual_total = 0

for quarter, months in sales.items():
    q_total = sum(months.values())
    annual_total += q_total
    print(f"\\n{quarter} (Total: \${q_total:,})")
    print("-" * 30)

    for month, amount in months.items():
        bar = "#" * (amount // 1000)
        print(f"  {month}: \${amount:>7,}  {bar}")

print("=" * 50)
print(f"Annual Total: \${annual_total:,}")
print(f"Monthly Avg:  \${annual_total // 12:,}")

# Best month
best_month = max(
    ((month, amount) for months in sales.values() for month, amount in months.items()),
    key=lambda x: x[1]
)
print(f"Best Month:   {best_month[0]} (\${best_month[1]:,})")
\`\`\`

Output (excerpt):
\`\`\`
==================================================
               ANNUAL SALES REPORT
==================================================

Q1 (Total: $39,500)
------------------------------
  Jan: $ 12,500  ############
  Feb: $ 11,200  ###########
  Mar: $ 15,800  ###############
...
==================================================
Annual Total: $183,100
Monthly Avg:  $15,258
Best Month:   Dec ($22,500)
\`\`\`

> [!TIP]
> Use \`for key in dict\` to iterate keys only. Use \`for key, value in dict.items()\` when you need both - this is the most common pattern. Never modify the dictionary structure (add/remove keys) during iteration - iterate over \`list(dict.keys())\` instead, or build a new dict with comprehension.`,
  objectives: [
    "Iterate over dictionary keys using a for loop.",
    "Iterate over values using .values().",
    "Iterate over key-value pairs using .items() - the most common pattern.",
    "Sort dictionary iteration by key or value.",
    "Safely modify a dictionary during iteration."
  ],
  difficulty: "beginner",
  xpReward: 60
};

// prisma/notes/2.1 Data Structures/Dictionaries/dictionary-vs-json.ts
var dictionaryVsJsonLesson = {
  title: "Dictionary vs JSON",
  slug: "dictionary-vs-json",
  content: `# Dictionary vs JSON

## What is JSON?

**JSON** (JavaScript Object Notation) is a text-based data format used to exchange data between systems - between a Python backend and a web browser, between APIs, or for storing configuration. JSON looks very similar to Python dictionaries, which is why understanding the relationship between them is important.

\`\`\`json
{
    "name": "Alice",
    "age": 25,
    "active": true,
    "scores": [88, 92, 75],
    "address": null
}
\`\`\`

## Similarities Between Python Dict and JSON

\`\`\`
Feature            Python Dict         JSON
-----------------  ------------------  ------------------
Structure          key: value          "key": value
Nesting            Supported           Supported
Lists/Arrays       list []             array []
Strings            'text' or "text"    "text" only
Numbers            int, float          number
Booleans           True, False         true, false
Null/None          None                null
\`\`\`

## Key Differences

\`\`\`
Difference         Python Dict         JSON
-----------------  ------------------  --------------------
Booleans           True, False         true, false
Null value         None                null
String quotes      Single or double    Double quotes ONLY
Key types          Any immutable       Strings ONLY
Comments           No (in data)        Not supported
Trailing commas    Allowed             Not allowed
\`\`\`

\`\`\`python
# Python dict
python_dict = {
    "name": "Alice",
    "active": True,       # Python: True
    "score": None,        # Python: None
    42: "a number key",   # Python: any immutable key
}

# Equivalent JSON (strings only, different bool/null)
json_string = '''
{
    "name": "Alice",
    "active": true,
    "score": null
}
'''
# Note: 42 as a key is not valid JSON (must be a string)
\`\`\`

## The json Module

Python's built-in \`json\` module handles all conversions between Python dicts and JSON strings.

\`\`\`python
import json
\`\`\`

## Converting Python Dict to JSON String (Serialization)

### json.dumps() - Dict to JSON String

\`\`\`python
import json

person = {
    "name": "Alice",
    "age": 25,
    "active": True,
    "score": None,
    "hobbies": ["reading", "coding"]
}

# Convert to JSON string
json_string = json.dumps(person)
print(json_string)
print(type(json_string))   # Output: <class 'str'>
\`\`\`

Output:
\`\`\`
{"name": "Alice", "age": 25, "active": true, "score": null, "hobbies": ["reading", "coding"]}
<class 'str'>
\`\`\`

Notice how Python's \`True\` became JSON's \`true\` and Python's \`None\` became JSON's \`null\`.

### Pretty Printing JSON

\`\`\`python
import json

person = {
    "name": "Alice",
    "age": 25,
    "address": {"city": "New York", "zip": "10001"},
    "scores": [88, 92, 75]
}

# indent parameter makes it human-readable
pretty = json.dumps(person, indent=4)
print(pretty)
\`\`\`

Output:
\`\`\`json
{
    "name": "Alice",
    "age": 25,
    "address": {
        "city": "New York",
        "zip": "10001"
    },
    "scores": [
        88,
        92,
        75
    ]
}
\`\`\`

\`\`\`python
# Additional options
json.dumps(person, indent=2, sort_keys=True)      # Sort keys alphabetically
json.dumps(person, indent=2, ensure_ascii=False)  # Allow non-ASCII (\xE9, \xF1, \u4E2D)
json.dumps(person, separators=(',', ':'))          # Compact - no spaces
\`\`\`

## Converting JSON String to Python Dict (Deserialization)

### json.loads() - JSON String to Dict

\`\`\`python
import json

json_string = '{"name": "Alice", "age": 25, "active": true, "score": null}'

# Convert JSON string to Python dict
python_dict = json.loads(json_string)
print(python_dict)
print(type(python_dict))   # Output: <class 'dict'>

# JSON 'true' became Python True, JSON 'null' became Python None
print(python_dict["active"])   # Output: True  (Python bool)
print(python_dict["score"])    # Output: None  (Python None)
\`\`\`

\`\`\`python
# JSON array becomes Python list
json_array = '[1, 2, 3, "hello", true, null]'
python_list = json.loads(json_array)
print(python_list)         # Output: [1, 2, 3, 'hello', True, None]
print(type(python_list))   # Output: <class 'list'>
\`\`\`

## Working with JSON Files

### Writing a Dict to a JSON File

\`\`\`python
import json

data = {
    "students": [
        {"name": "Alice", "grade": "A", "score": 92},
        {"name": "Bob",   "grade": "B", "score": 85},
        {"name": "Charlie","grade":"A", "score": 95}
    ],
    "class": "CS101",
    "semester": "Fall 2024"
}

# json.dump() - write to a file (note: no 's')
with open("students.json", "w") as file:
    json.dump(data, file, indent=4)

print("Data written to students.json")
\`\`\`

### Reading a JSON File into a Dict

\`\`\`python
import json

# json.load() - read from a file (note: no 's')
with open("students.json", "r") as file:
    loaded_data = json.load(file)

print(type(loaded_data))   # Output: <class 'dict'>
print(loaded_data["class"])   # Output: CS101

for student in loaded_data["students"]:
    print(f"{student['name']}: {student['grade']}")
\`\`\`

## Type Conversion Table

\`\`\`
Python Type    JSON Type      Python Type (after loading)
-----------    ---------      ---------------------------
dict           object {}      dict
list           array []       list
tuple          array []       list  (tuples become lists!)
str            string ""      str
int            number         int
float          number         float
True           true           True
False          false          False
None           null           None
\`\`\`

\`\`\`python
import json

# Tuples become lists after JSON round-trip!
original = {"point": (10, 20)}
json_str = json.dumps(original)
print(json_str)     # Output: {"point": [10, 20]}

loaded = json.loads(json_str)
print(loaded["point"])            # Output: [10, 20]
print(type(loaded["point"]))      # Output: <class 'list'>  (was tuple!)
\`\`\`

## Handling JSON Errors

\`\`\`python
import json

# Invalid JSON string
bad_json = "{'name': 'Alice'}"   # Single quotes - invalid JSON!

try:
    data = json.loads(bad_json)
except json.JSONDecodeError as e:
    print(f"JSON Error: {e}")
# Output: JSON Error: Expecting property name enclosed in double quotes...
\`\`\`

## Real-World Example: Working with an API Response

\`\`\`python
import json

# Simulated API response (what you would get from requests.get().json())
api_response = """
{
    "status": "success",
    "data": {
        "user": {
            "id": 12345,
            "username": "alice_smith",
            "email": "alice@example.com",
            "premium": true,
            "last_login": "2024-01-15"
        },
        "permissions": ["read", "write", "export"],
        "quota": {
            "used": 2048,
            "total": 10240,
            "unit": "MB"
        }
    },
    "message": null
}
"""

# Parse the response
response = json.loads(api_response)

# Extract data
user = response["data"]["user"]
permissions = response["data"]["permissions"]
quota = response["data"]["quota"]

print(f"User      : {user['username']}")
print(f"Email     : {user['email']}")
print(f"Premium   : {user['premium']}")
print(f"Permissions: {', '.join(permissions)}")

used_pct = (quota["used"] / quota["total"]) * 100
print(f"Storage   : {quota['used']} / {quota['total']} {quota['unit']} ({used_pct:.1f}%)")
print(f"Message   : {response['message']}")   # Prints: None

# Modify and save back to JSON
user["email"] = "alice.smith@example.com"
print("\\nUpdated JSON:")
print(json.dumps(response["data"]["user"], indent=2))
\`\`\`

Output:
\`\`\`
User      : alice_smith
Email     : alice@example.com
Premium   : True
Permissions: read, write, export
Storage   : 2048 / 10240 MB (20.0%)
Message   : None

Updated JSON:
{
  "id": 12345,
  "username": "alice_smith",
  "email": "alice.smith@example.com",
  "premium": true,
  "last_login": "2024-01-15"
}
\`\`\`

## Quick Reference

\`\`\`python
import json

# Dict -> JSON string
json_str = json.dumps(my_dict)              # Compact
json_str = json.dumps(my_dict, indent=4)    # Pretty

# JSON string -> Dict
my_dict = json.loads(json_str)

# Dict -> JSON file
with open("file.json", "w") as f:
    json.dump(my_dict, f, indent=4)

# JSON file -> Dict
with open("file.json", "r") as f:
    my_dict = json.load(f)
\`\`\`

> [!TIP]
> Remember the four functions: \`dumps()\` and \`loads()\` for strings (the 's' stands for 'string'), \`dump()\` and \`load()\` for files. Also remember that JSON requires double quotes for strings and uses \`true\`/\`false\`/\`null\` (lowercase) - Python's \`True\`/\`False\`/\`None\` are automatically converted.`,
  objectives: [
    "Understand the similarities and differences between Python dicts and JSON.",
    "Use json.dumps() to convert a Python dictionary to a JSON string.",
    "Use json.loads() to convert a JSON string to a Python dictionary.",
    "Use json.dump() and json.load() to write and read JSON files.",
    "Understand how Python types map to JSON types and vice versa."
  ],
  difficulty: "intermediate",
  xpReward: 65
};

